module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

reg [$clog2(DEPTH)-1:0] wptr, rptr, wptr_syn, rptr_syn;

always @(posedge wclk) begin
    if (!wrstn) begin
        wptr <= 0;
    end else if (winc) begin
        wptr <= wptr + 1;
    end
end

always @(posedge wclk) begin
    wptr_syn <= wptr;
end

always @(posedge rclk) begin
    if (!rrstn) begin
        rptr <= 0;
    end else if (rinc) begin
        rptr <= rptr + 1;
    end
end

always @(posedge rclk) begin
    rptr_syn <= rptr;
end

assign wfull = (wptr_syn == {~rptr_syn[ADDR_WIDTH:ADDR_WIDTH-1], rptr_syn[ADDR_WIDTH-2:0]});
assign rempty = (rptr_syn == wptr_syn);

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
